command:
// ======================================
// Roguelike 集合宏管理器
// ======================================
// 打开集合宏管理器，GM可以创建集合宏。
// 集合宏允许玩家从多个配置的抽取宏中选择一个执行。
// ======================================

if (!game.user.isGM) {
  ui.notifications.error('只有 GM 可以使用集合宏管理器');
} else {
  const mod = game.modules.get('ai-pf2e-assistant');
  if (!mod?.api?.roguelike?.openCollectionManager) {
    ui.notifications.warn('Roguelike 集合宏管理器不可用，请确认模块已启用');
  } else {
    mod.api.roguelike.openCollectionManager();
  }
}
